	// Create a channel to signal completion
	done := make(chan struct{})
	var result goja.Value
	var runErr error

	go func() {
		defer close(done)
		// Inject the order object as a global variable 'order'.
		// This prevents ReferenceError when the script tries to access 'order'.
		if err := vm.Set("order", order); err != nil {
			// If setting the variable fails, abort
			runErr = fmt.Errorf("failed to inject variable order: %w", err)
			return
		}

