		}
	case <-time.After(timeout):
		// Timeout reached: stop the VM to free resources
		// Note: goja does not support interrupting running goroutines directly via API.
		// The VM object should be discarded after timeout.
		return 0.0, fmt.Errorf("script execution timed out after %v", timeout)
	}

	// Convert result to float64
	exported := result.Export()
	discount, ok := exported.(float64)
	if !ok {
		// Try to convert from other numeric types (e.g., int, float32)
		switch v := exported.(type) {
