	// We use a channel to signal completion or timeout.
	done := make(chan struct{}, 1)
	var result goja.Value
	var execErr error

	go func() {
		defer func() {
			if r := recover(); r != nil {
				execErr = fmt.Errorf("script panic: %v", r)
			}
			done <- struct{}{}
		}()
		result, execErr = vm.RunString(script)
	}()

	select {
	case <-done:
